using System.Net;
using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();

// Breaking change: ValidateScopes is now enabled in development (.NET 9).
// A scoped service (IUserService) cannot be resolved from the root provider
// inside a singleton factory. Changed to AddScoped to fix the captive dependency.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// Breaking change: HttpClientFactory now uses SocketsHttpHandler by default (.NET 9).
// The cast to HttpClientHandler throws InvalidCastException at runtime.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });

builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // Breaking change: ForwardedHeadersMiddleware now ignores X-Forwarded-*
    // headers from proxies not in KnownProxies/KnownNetworks (.NET 9).
    // TODO: Replace with your actual reverse-proxy IP address(es).
    options.KnownProxies.Add(IPAddress.Parse("10.0.0.1"));
});

// Breaking change: HttpClientFactory redacts all header values in Trace-level
// logs by default (.NET 9). Allowlist non-sensitive headers for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h => h is "Authorization" or "Cookie" or "Set-Cookie"));

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

